mapper.select:
SELECT m.id, b.brand_name as menteeName, b.mentee_user_id as menteeUserId, b.avator as menteeAvatar, m.past_year_messages as pastYearMessages, m.guidance_period_earning as guidancePeriodEarning, m.guidance_period_influencers as guidancePeriodInfluencers, m.guidance_period_messages as guidancePeriodMessages, m.status, m.create_at createAt FROM mentorship m INNER JOIN brand b ON m.mentee_brand_id = b.id WHERE m.mentor_brand_id = #{mentorBrandId}
AND locate(#{dto.q}, b.brand_name)>0
AND m.status = #{dto.status}
ORDER BY m.create_at DESC
